Here's a very basic example of what the code might look like:

```javascript
function updateSheetWithCalendarEvents() {
  var calendar = CalendarApp.getDefaultCalendar();
  var now = new Date();
  var events = calendar.getEvents(now, new Date(now.getFullYear() + 1, now.getMonth(), now.getDate()));
  var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();

  for (var i = 0; i < events.length; i++) {
    var event = events[i];
    sheet.appendRow([event.getTitle(), event.getDescription(), event.getStartTime(), event.getEndTime()]);
